import { PaymentServiceFactory } from './PaymentServiceFactory';
import { PaymentMethod, PaymentRequest, PaymentResult } from '../../types/payment';
import { v4 as uuidv4 } from 'uuid';

/**
 * Сервис для обработки платежей
 */
export class PaymentProcessorService {
  /**
   * Обрабатывает платеж с выбранным методом оплаты
   * @param method Выбранный метод оплаты
   * @param amount Сумма платежа
   * @param description Описание платежа
   * @param customerId Идентификатор клиента (опционально)
   * @param metadata Дополнительные данные для платежа (опционально)
   * @returns Результат инициализации платежа
   */
  public static async processPayment(
    method: PaymentMethod,
    amount: number,
    description: string,
    customerId?: string,
    metadata?: Record<string, any>
  ): Promise<PaymentResult> {
    try {
      // Генерируем уникальный ID заказа
      const orderId = uuidv4();
      
      // Базовый URL для возврата после оплаты
      const baseUrl = window.location.origin;
      const returnUrl = `${baseUrl}/payment/result?orderId=${orderId}`;
      
      // Формируем запрос на оплату
      const paymentRequest: PaymentRequest = {
        amount,
        description,
        orderId,
        returnUrl
      };
      
      // Получаем нужный сервис по выбранному методу
      const paymentService = PaymentServiceFactory.createPaymentService(method);
      
      // Инициируем платеж
      const result = await paymentService.initiatePayment(paymentRequest);
      
      // Если платеж успешно инициирован и есть URL для перенаправления
      if (result.success && result.redirectUrl) {
        // Здесь можно сохранить информацию о платеже в базу данных
        await this.savePaymentInfo(result.transactionId!, method, amount, customerId, metadata);
        
        // Перенаправляем пользователя на страницу оплаты
        window.location.href = result.redirectUrl;
      }
      
      return result;
    } catch (error) {
      console.error('Payment processing error:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Ошибка при обработке платежа'
      };
    }
  }
  
  /**
   * Проверяет статус платежа
   * @param transactionId Идентификатор транзакции
   * @param method Метод оплаты
   * @returns Результат проверки статуса
   */
  public static async checkPaymentStatus(
    transactionId: string,
    method: PaymentMethod
  ): Promise<PaymentResult> {
    try {
      const paymentService = PaymentServiceFactory.createPaymentService(method);
      return await paymentService.checkPaymentStatus(transactionId);
    } catch (error) {
      console.error('Payment status check error:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Ошибка при проверке статуса платежа'
      };
    }
  }
  
  /**
   * Сохраняет информацию о платеже в базу данных
   * В этом примере метод заглушка, в реальном приложении здесь должно быть
   * сохранение в Firebase или другую базу данных
   */
  private static async savePaymentInfo(
    transactionId: string,
    method: PaymentMethod,
    amount: number,
    customerId?: string,
    metadata?: Record<string, any>
  ): Promise<void> {
    // Здесь должна быть реализация сохранения в базу данных
    console.log('Saving payment info:', {
      transactionId,
      method,
      amount,
      customerId,
      metadata,
      timestamp: new Date().toISOString()
    });
  }
}
